grid:








































































































        select 'this._voucherCode='@@id';load$GridVoucherDetail$(this);' as message
return




        select 'dispose$GridVoucherDetail$(this);' as message
return






      /* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    nguyen_gia: '[nguyen_gia]:=[nguyen_gia_nt]*[$ty_gia]',
    gt_da_kh : '[gt_da_kh]:=[gt_da_kh_nt]*[$ty_gia]',
    gt_kh_ky: '[gt_kh_ky]:=[gt_kh_ky_nt]*[$ty_gia]',
    gt_kh_ky_tl: '[gt_kh_ky]:=[$so_ky_kh] == 0 ? 0 : [nguyen_gia]/[$so_ky_kh]',
    gt_cl: '[gt_cl]:=[gt_cl_nt]*[$ty_gia]',
    gt_da_kh00: '[gt_da_kh00]:=[gt_da_kh00_nt]*[$ty_gia]',

    gt_cl_nt: '[gt_cl_nt]:=[nguyen_gia_nt] - [gt_da_kh_nt]',
    gt_cl_tl: '[gt_cl]:=[nguyen_gia] - [gt_da_kh]',
    gt_kh_ky_nt: '[gt_kh_ky_nt]:=[$so_ky_kh] == 0 ? 0 : [nguyen_gia_nt]/[$so_ky_kh]',
    gt_kh_ky_nt0: '[gt_kh_ky_nt]:=0',
    gt_kh_ky0: '[gt_kh_ky]:=0',

    t_nguyen_gia_nt: ['t_nguyen_gia_nt', 'nguyen_gia_nt'],
    t_gt_da_kh_nt: ['t_gt_da_kh_nt', 'gt_da_kh_nt'],
    t_gt_cl_nt: ['t_gt_cl_nt', 'gt_cl_nt'],
    t_gt_kh_ky_nt: ['t_gt_kh_ky_nt', 'gt_kh_ky_nt'],

    t_nguyen_gia: ['t_nguyen_gia', 'nguyen_gia'],
    t_gt_da_kh: ['t_gt_da_kh', 'gt_da_kh'],
    t_gt_cl: ['t_gt_cl', 'gt_cl'],
    t_gt_kh_ky: ['t_gt_kh_ky', 'gt_kh_ky']
  };
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  var kieu_kh = f.getItemValue('kieu_kh');
  var so_ky_kh = f.getItemValue('so_ky_kh');
  switch (name) {
    case 'nguyen_gia_nt':
      if (so_ky_kh > 0 && kieu_kh == 0) g.validExpression(o, [g.$a.nguyen_gia, g.$a.gt_cl_nt, g.$a.gt_kh_ky_nt, g.$a.gt_kh_ky, g.$a.gt_cl], [g.$a.t_nguyen_gia_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_kh_ky_nt, g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_kh_ky]);
        else g.validExpression(o, [g.$a.nguyen_gia, g.$a.gt_cl_nt, g.$a.gt_kh_ky_nt0, g.$a.gt_kh_ky, g.$a.gt_cl], [g.$a.t_nguyen_gia_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_kh_ky_nt, g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_kh_ky]);
      break;
    case 'gt_da_kh_nt':
      g.validExpression(o, [g.$a.gt_da_kh, g.$a.gt_cl_nt, g.$a.gt_cl], [g.$a.t_gt_da_kh_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_da_kh, g.$a.t_gt_cl]);
      break;
    case 'gt_cl_nt':
      g.validExpression(o, [g.$a.gt_cl], [g.$a.t_gt_cl_nt, g.$a.t_gt_cl]);
      break;
    case 'gt_kh_ky_nt':
      g.validExpression(o, [g.$a.gt_kh_ky], [g.$a.t_gt_kh_ky_nt, g.$a.t_gt_kh_ky]);
      break;
    case 'gt_da_kh00_nt':
      g.validExpression(o, [g.$a.gt_da_kh00]);
      break;
    case 'nguyen_gia':
      if (so_ky_kh > 0 && kieu_kh == 0) g.validExpression(o, [g.$a.gt_kh_ky_tl, g.$a.gt_cl_tl], [g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_kh_ky]);
        else g.validExpression(o, [g.$a.gt_kh_ky0, g.$a.gt_cl_tl], [g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_kh_ky]);
      break;
    case 'gt_da_kh':
      g.validExpression(o, [g.$a.gt_cl_tl], [g.$a.t_gt_da_kh, g.$a.t_gt_cl]);
      break;
    case 'gt_kh_ky':
      g.validExpression(o, null, [g.$a.t_gt_kh_ky]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {g.executeAggregate([g.$a.t_nguyen_gia_nt, g.$a.t_gt_da_kh_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_kh_ky_nt, g.$a.t_nguyen_gia, g.$a.t_gt_da_kh, g.$a.t_gt_cl, g.$a.t_gt_kh_ky]);}
/* </flatten> */







